sql:
SELECT category_name, AVG(CAST(power_consumption AS INT)) AS average_power_consumption
FROM iot_categories
GROUP BY category_name;

SELECT category_name, power_consumption 
FROM iot_categories 
WHERE power_consumption = (SELECT MAX(power_consumption) FROM iot_categories);

SELECT iot_categories.category_name, network_resources.resource_name
FROM iot_categories
INNER JOIN network_resources ON iot_categories.category_id = network_resources.category_id;

SELECT AVG(CAST(power_consumption AS REAL)) AS average_power_consumption
FROM iot_categories
WHERE max_connections = (SELECT MAX(max_connections) FROM iot_categories);

SELECT category_name, bandwidth
FROM iot_categories
WHERE security_features LIKE '%AES-128%';

SELECT category_name, SUM(CAST(power_consumption AS REAL)) AS total_power_consumption
FROM iot_categories
GROUP BY category_name;

SELECT resource_name 
FROM network_resources
WHERE current_usage = (SELECT MAX(current_usage) FROM network_resources);

SELECT category_name, bandwidth, ul_bitrate
FROM iot_categories
ORDER BY bandwidth DESC, ul_bitrate DESC;

SELECT category_name, release
FROM iot_categories
WHERE bandwidth > '15MHz' AND last_updated > '2023-01-01';

SELECT category_name, bandwidth
FROM iot_categories
ORDER BY category_name ASC;

SELECT geographical_location, COUNT(resource_id)
FROM network_resources
GROUP BY geographical_location;

SELECT category_name, power_consumption
FROM iot_categories
ORDER BY power_consumption DESC;

SELECT category_name, max_connections
FROM iot_categories
WHERE max_connections IS NOT NULL;

SELECT resource_id, resource_name, (resource_capacity - current_usage) AS available_capacity
FROM network_resources
ORDER BY available_capacity DESC;

SELECT COUNT(DISTINCT category_id) 
FROM network_resources 
WHERE resource_status = 'active';

SELECT release, AVG(max_connections) AS avg_max_connections, AVG(CAST(power_consumption AS REAL)) AS avg_power_consumption
FROM iot_categories
GROUP BY release;
